"""
MKT Original Commentary — Jeremiah chapters 28–30 (fill script)
Run: python3 scripts/zc-original-jeremiah-28-30-fill.py

Key translation decisions:
- 28:2: lo shelahtikha YHWH — "the LORD has not sent you" — the triple disavowal
- 28:9: hanavi asher yinbave leshalom — the peace-prophet's credibility deferred to fulfillment
- 28:13: wood yokes → iron yokes — Hananiah's act intensifies rather than breaks the judgment
- 29:7: drosh et shalom ha-ir — "seek the welfare of the city" — exile ethics of civic engagement
- 29:10: kimlot l'Vavel shivim shanah — seventy years for Babylon
- 29:11: machashavot leshalom — plans for welfare (shalom), not for harm (ra'ah)
- 29:13: the Deuteronomic condition now stated as promise: seek and you will find
- 30:3: shavti et-shvut — double-shub restoration formula
- 30:7: et-tsarah hi l'Ya'aqov — the time of Jacob's trouble
- 30:9: David their king, raised up — Messianic/Davidic restoration
- 30:21: their leader from among them, brought near — indigenous covenant leadership
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JEREMIAH = {
"28": {
"1": "<p>The dating formula is unusually precise: <em>baššānâ hahîʾ bĕrēʾšît mamlekût Ṣidqiyyāhû... bašššānâ hārĕbîʿît baḥōdeš haḥămîšî</em> — &quot;in that same year, at the beginning of Zedekiah&apos;s reign, in the fourth year, in the fifth month.&quot; The dating aligns with the wider context of ch. 27 where Jeremiah wore the wooden yoke before the envoys of surrounding nations. Hananiah the son of Azzur (<em>ben-ʿAzzûr</em>) is identified as &quot;the prophet from Gibeon&quot; — a named opponent who functions as a case study in false prophecy. The MKT preserves all the chronological markers because they function as verifiable historical grounding.</p>",
"2": "<p><strong>šābart ʾet-ʿōl melek Bābel</strong> — &quot;I have broken the yoke of the king of Babylon&quot;; Hananiah&apos;s oracle uses the same first-person divine voice as Jeremiah&apos;s oracles, the same divine titles (<em>YHWH ṣĕbāʾôt ʾĕlōhê Yiśrāʾēl</em>), and the same prophetic formula (<em>kōh-ʾāmar YHWH</em>). The counterfeit oracle is structurally identical to genuine oracles — the only difference is content. The MKT renders Hananiah&apos;s oracle straightforwardly to show how plausible it sounded: &quot;I have broken the yoke of the king of Babylon.&quot;</p>",
"3": "<p><strong>bĕʿōd šĕnatayim yāmîm</strong> — &quot;within two years&quot;; Hananiah&apos;s timeline — two years — is specific and testable. He specifies the return of the temple vessels taken under Jehoiakim (605 BC). The specificity of the timeline makes this prophecy falsifiable in a way that vague promises are not; the same specificity that lends credibility will ultimately expose it as false. The MKT renders &quot;within two years&quot; literally to preserve the testability.</p>",
"4": "<p>Hananiah extends his oracle to include Jeconiah (Jehoiachin) himself and all the exiles of Judah who went to Babylon with him. The phrase <em>nĕʾûm-YHWH</em> (declares the LORD) closes the oracle — the same authenticating formula used in genuine prophecy. The comprehensive scope (temple vessels + the king + all exiles) makes this the most optimistic possible oracle at the most politically fraught moment.</p>",
"5": "<p>Jeremiah&apos;s response is remarkable for its lack of immediate counter-attack: he speaks &quot;in the presence of the priests and all the people who were standing in the temple&quot; — the full public setting. The confrontation is not private; both prophets&apos; reputations are on the line before the community. The MKT preserves the audience specification because the public nature of the confrontation gives the subsequent events their narrative weight.</p>",
"6": "<p><strong>ʾāmēn kēn yaʿăśeh YHWH</strong> — &quot;Amen! May the LORD do so!&quot; Jeremiah&apos;s startling &quot;Amen&quot; — he genuinely wishes the oracle were true. &quot;May the LORD fulfill the words you have prophesied (<em>yāqem YHWH ʾet-dĕbārêkā ʾăšer nitbāʾtā</em>)&quot; — an authentic expression of longing for the exile to end and the vessels to return. The MKT renders this as a sincere blessing rather than irony; Jeremiah&apos;s subsequent &quot;but&quot; in v.7 is what introduces the challenge, not sarcasm in v.6.</p>",
"7": "<p><strong>ʾak šĕmaʿ-nāʾ haddābār hazzeh</strong> — &quot;But hear now this word&quot;; the adversative <em>ʾak</em> (but, however) marks the transition from Jeremiah&apos;s sincere blessing to his challenge. The word Jeremiah speaks is addressed both to Hananiah and to &quot;all the people&quot; (<em>bĕʾoznê kol-hāʿām</em>). The public audience is maintained — the counter-challenge must be heard by all who heard Hananiah&apos;s oracle.</p>",
"8": "<p><strong>hannĕbîʾîm ʾăšer hāyû lĕpānay ûlĕpānêkā mēʿôlām</strong> — &quot;The prophets who preceded you and me from of old&quot;; Jeremiah appeals to the prophetic tradition as evidence. The historical pattern: authentic prophets (<em>nābāʾ ʿal-ʾărāṣôt rabbôt wĕʿal-mamlākôt gĕdōlôt</em>, against many lands and great kingdoms) characteristically prophesied war (<em>milhāmâ</em>), disaster (<em>rāʿâ</em>), and plague (<em>deber</em>). The MKT preserves the threefold list — war, disaster, plague — as the standard pattern of classical prophecy, which is the opposite of Hananiah&apos;s message.</p>",
"9": "<p><strong>hanābîʾ ʾăšer yinnābēʾ lĕšālôm</strong> — &quot;As for the prophet who prophesies peace&quot;; the epistemological problem of peace-prophecy. For judgment prophecy: the tradition and moral coherence of YHWH&apos;s character can validate it in advance. For peace prophecy: <em>bĕbôʾ dĕbar hannābîʾ yiwwādaʿ hannābîʾ</em> — &quot;only when his word comes true will the prophet be known as one truly sent by the LORD.&quot; The future-fulfillment criterion applies uniquely to positive oracles. The MKT&apos;s &quot;only when his word comes true&quot; preserves the deferred-validation principle that will be vindicated in v.17.</p>",
"10": "<p><strong>wayyiqqaḥ ḥananyāhû hannābîʾ ʾet-hammôṭâ</strong> — &quot;Then Hananiah took the yoke bar&quot;; <em>mōṭâ</em> (yoke bar, yoke pole) — the symbol Jeremiah had been wearing publicly. Hananiah&apos;s dramatic breaking of the bar (<em>wayĕšabbĕrēhû</em>) is a prophetic counter-sign: the yoke-breaking is his enacted oracle. In prophetic tradition, symbolic actions were not merely illustrative but effective; by breaking the yoke, Hananiah claimed to be enacting YHWH&apos;s redemptive act. The MKT renders the action narrative directly: &quot;broke it.&quot;</p>",
"11": "<p><strong>kāzōʾt ʾešbōr ʾet-ʿōl Nĕbûkadrĕʾṣar melek Bābel</strong> — &quot;This is how I will break the yoke of Nebuchadnezzar king of Babylon&quot;; Hananiah interprets his own sign-act before the whole people. The public proclamation in Hananiah&apos;s words parallels YHWH&apos;s own proclamation-form. &quot;And the prophet Jeremiah went his way&quot; (<em>wayyēlek yirmĕyāhû lĕdarkô</em>) — Jeremiah&apos;s departure is significant: he does not counter immediately but waits for a fresh divine word.</p>",
"12": "<p>The structure of divine response: Jeremiah does not speak on his own authority but waits for the word of YHWH to come (<em>wayĕhî dĕbar-YHWH ʾel-yirmĕyāhû ʾaḥărê šĕbōr ḥananyāhû hannābîʾ ʾet-hammôṭâ</em>). The temporal note &quot;after Hananiah had broken the yoke bar&quot; makes clear that this is a responsive word — YHWH addresses what Hananiah has done. The MKT preserves the causal relationship: the divine word responds to the prophetic action.</p>",
"13": "<p><strong>môṭôt ʿēts šābartā ûʿāśîtā taḥtêhen môṭôt barzĕl</strong> — &quot;You have broken yokes of wood, but you have made yokes of iron to replace them&quot;; the terrible irony: Hananiah&apos;s act of breaking the wooden yoke (<em>ʿōl ʿēts</em>) has resulted in an iron yoke (<em>ʿōl barzĕl</em>) being imposed. The symbolic act intended to enact liberation has enacted a heavier bondage. The MKT renders the irony starkly: wood broken, iron made.</p>",
"14": "<p><strong>ʿōl barzĕl nātattî ʿal-ṣawwĕʾar kol-haggôyim hāʾēlleh</strong> — &quot;I have placed a yoke of iron on the neck of all these nations so that they may serve Nebuchadnezzar&quot;; YHWH&apos;s own interpretation of the iron yoke. The phrase &quot;including the wild animals&quot; (<em>wĕgam ʾet-ḥayyat haśśādeh nātattî lô</em>) — the dominion given to Nebuchadnezzar is comprehensive, including the animal kingdom. The MKT preserves &quot;wild animals&quot; as a specific addition that emphasizes the totality of Babylon&apos;s divinely-granted sovereignty.</p>",
"15": "<p><strong>šĕmaʿ-nāʾ ḥananyāhû lōʾ-šĕlaḥăkā YHWH</strong> — &quot;Listen, Hananiah! The LORD has not sent you&quot;; the direct confrontation Jeremiah had withheld in v.6-9 now comes. The triple disavowal of 14:14 (<em>lōʾ šĕlaḥtîm... wĕlōʾ ṣiwwîtîm... wĕlōʾ dibbartî</em>) is here compressed into the single decisive verb: &quot;not sent you.&quot; The charge: <em>wĕʾattâ hibṭaḥtā ʾet-hāʿām hazzeh ʿal-šāqer</em> — &quot;you have made this people trust in a lie.&quot;</p>",
"16": "<p><strong>hinnĕnî mĕšallĕḥăkā mēʿal pĕnê hāʾădāmâ</strong> — &quot;I am about to remove you from the face of the earth&quot;; the verb <em>šālaḥ</em> (send) appears ironically: YHWH did not send (<em>šālaḥ</em>) Hananiah (v.15), but now YHWH is sending (<em>mĕšallĕḥăkā</em>) him — from life. &quot;This very year you will die (<em>tāmût</em>), because you have spoken rebellion against the LORD&quot; (<em>sārāh dibbartā ʾel-YHWH</em>). The specific &quot;this year&quot; (<em>bašššānâ hazzōʾt</em>) will be tested by v.17.</p>",
"17": "<p><strong>wayyāmat ḥananyāhû hannābîʾ bašššānâ hahîʾ baḥōdeš haššĕbîʿî</strong> — &quot;And the prophet Hananiah died that same year, in the seventh month&quot;; the narrative fulfillment completes the prophetic contest. The seventh month (two months after the fifth-month confrontation of v.1) and the same year — precise temporal verification. The narrative mentions Hananiah&apos;s title &quot;the prophet&quot; even in his death — the ironic designation of the false prophet who died. The MKT&apos;s literal rendering preserves the narrative&apos;s deliberate precision.</p>"
},
"29": {
"1": "<p><strong>wĕʾēlleh dibrê-hassēper ʾăšer šālaḥ yirmĕyāhû hannābîʾ</strong> — &quot;These are the words of the letter that the prophet Jeremiah sent&quot;; <em>sēper</em> (letter, document, scroll) — a formal written communication carried by official envoys. The recipients are specified in layers: &quot;surviving elders among the exiles&quot; (<em>yeter ziknê haggôlâ</em>), priests, prophets, and all the people. &quot;Surviving elders&quot; (<em>yeter</em>) implies some had already died — the exile was not gentle. The MKT preserves &quot;surviving&quot; to acknowledge the mortality within the exile community.</p>",
"2": "<p>The chronological anchoring: <em>ʾaḥărê ṣēt Yĕkonyāhû hammelek wĕhaggĕbîrâ wĕhassārîsîm śārê Yĕhûdâ wîrûšālaim wĕheḥārāš wĕhammasger</em> — after King Jeconiah, the queen mother, court officials, princes, craftsmen, and metalworkers had been taken to Babylon. The fullness of the leadership vacuum is specified: king, queen mother, officials, princes, skilled workers — all the pillars of a functioning society removed.</p>",
"3": "<p>The letter is entrusted to <em>Ĕlāśāh ben-Šāpān ûGĕmaryāhû ben-Ḥilqiyyāhû</em> — named emissaries of Zedekiah on official diplomatic business with Nebuchadnezzar. Jeremiah uses the official diplomatic channel to send his pastoral letter. The names matter: the Shaphan family were supporters of Jeremiah (cf. 26:24), and Hilkiah was the high priest who found the book of the law in Josiah&apos;s day (2 Kgs 22:8). The letter travels in trustworthy hands.</p>",
"4": "<p><strong>ʾăšer hĕglêtî mîrûšālaim Bābĕlâ</strong> — &quot;whom I have sent into exile from Jerusalem to Babylon&quot;; YHWH&apos;s own ownership of the exile — not Nebuchadnezzar&apos;s conquest but YHWH&apos;s deportation. The pastoral letter begins by reframing the exile&apos;s cause: the exiles did not lose to Babylon; YHWH sent them. This reframing is essential to what follows — if YHWH sent them, YHWH can bring them back; if they simply lost a political contest, return is uncertain.</p>",
"5": "<p><strong>bĕnû bāttîm wĕšēbû... ṭĕʿû gannôt wĕʾiklû ʾet-pĕriyāhen</strong> — &quot;Build houses and settle in them; plant gardens and eat what they produce&quot;; two paired imperatives: build + settle, plant + eat. The verbs are positive engagement with life in Babylon — not temporary shelter or survival, but establishment. The instruction to plant and harvest implies a multi-year commitment: trees planted do not bear fruit immediately. The MKT&apos;s &quot;settle in them&quot; captures the permanence-intention in <em>šēbû</em> (dwell, settle).</p>",
"6": "<p><strong>qĕḥû nāšîm ûhôlîdû bānîm ûbānôt</strong> — &quot;Marry and have sons and daughters&quot;; the marriage-and-birth instruction directly reverses what Jeremiah was personally commanded in 16:1-4 (no marriage, because of the coming disaster). Jeremiah personally cannot marry; the exiles should marry and multiply. The instruction &quot;give your daughters to husbands and your sons to wives so that they too may multiply&quot; is a full community-multiplication program in exile. The MKT renders the parallelism of sons/daughters in all its symmetry.</p>",
"7": "<p><strong>wĕdirĕšû ʾet-šĕlôm hāʿîr ʾăšer higlêtî ʾetkem šāmmâ</strong> — &quot;Seek the welfare of the city where I have sent you into exile&quot;; <em>šālôm</em> of Babylon is YHWH&apos;s goal for the exiles. The same word Hananiah promised Israel (28:9 — <em>šālôm</em>) is to be the exiles&apos; gift to their captors. &quot;And pray to the LORD on its behalf&quot; (<em>wĕhitpallĕlû bĕʿādāh ʾel-YHWH</em>) — prayer for Babylon&apos;s welfare is a covenant obligation. The final clause: <em>kî bišlômāh yihyeh lākem šālôm</em> — &quot;for in its welfare you will have welfare&quot; — the unusual theological claim that Israelite flourishing is tied to Babylonian flourishing. The MKT preserves all three dimensions: seek, pray, because.</p>",
"8": "<p><strong>ʾal-yaššîʾû ʾetkem nĕbîʾêkem ʾăšer-bĕqirbĕkem</strong> — &quot;Do not let the prophets and diviners among you deceive you&quot;; the false prophets in Babylon parallel those in Jerusalem (28:1-17). <em>Kōsĕmîm</em> (diviners) alongside <em>nĕbîʾîm</em> (prophets) — the full range of false intermediaries. &quot;Do not listen to the dreams they are causing you to dream&quot; (<em>ʾal-tišmĕʿû ʾel-ḥalōmôtêkem ʾăšer ʾattem maḥlĕmîm</em>) — the unusual causative (&quot;dreams you are causing to dream&quot;) implies that the community&apos;s wish-fulfillment desires are generating these dreams.</p>",
"9": "<p><strong>kî bišĕqer hēm nĕbāʾîm lākem bišmî</strong> — &quot;For they are prophesying lies to you in my name&quot;; the triple disavowal: &quot;I have not sent them&quot; (<em>lōʾ šĕlaḥtîm</em>). The brevity of the disavowal contrasts with the formal prophetic oracle-form Hananiah deployed (28:2-4) — YHWH&apos;s refutation requires only one phrase.</p>",
"10": "<p><strong>kî kōh ʾāmar YHWH kimlōʾt lĕbābel šibʿîm šānâ</strong> — &quot;For thus says the LORD: When seventy years for Babylon are complete&quot;; the seventy-year timeframe (cf. 25:11-12) is given a positive reinterpretation: it is not just a period of punishment but a period with an end. <em>ʾEpqōd ʾetkem</em> (I will come to you, attend to you — the verb <em>pāqad</em> meaning to visit/attend) — the divine attention that has seemed absent will return. &quot;I will fulfill my good promise to bring you back to this place&quot; (<em>dĕbārî haṭṭôb</em>) — the restoration is a kept promise, not an afterthought. The MKT&apos;s &quot;good promise&quot; translates <em>haddābār haṭṭôb</em> (the good word/promise).</p>",
"11": "<p><strong>kî ʾānōkî yādaʿtî ʾet-hammaḥăšābôt ʾăšer ʾānōkî ḥōšēb ʿălêkem</strong> — &quot;For I know the plans I have for you, declares the LORD&quot;; the famous verse. <em>Maḥăšābôt</em> (thoughts, plans, purposes) — the same word used for YHWH&apos;s purposes in judgment (e.g. 18:11: <em>ḥōšēb ʿălêkem rāʿâ</em>). Here the <em>maḥăšābôt</em> are <em>lĕšālôm wĕlōʾ lĕrāʿâ</em> — for welfare (wholeness, peace) and not for harm. <em>Lātēt lākem ʾaḥărît wĕtiqwâ</em> — to give you a future (<em>ʾaḥărît</em> = end/afterward, the word for &quot;future&quot;) and a hope (<em>tiqwâ</em> = hope, also the word for a cord/rope — something that holds you). The MKT renders &quot;a future and a hope&quot; because both nouns carry forward momentum: <em>ʾaḥărît</em> is eschatological orientation; <em>tiqwâ</em> is present confidence about it.</p>",
"12": "<p><strong>ûqĕrāʾtem ʾōtî ûhălaktem wĕhitpallaltĕm ʾēlay</strong> — &quot;Then you will call on me and come and pray to me, and I will listen to you&quot;; the three verbs: call (<em>qārāʾ</em>), come (<em>hālaḵ</em>), pray (<em>hitpallēl</em>) — all three directing the exiles toward YHWH. The covenant relationship restored through prayer. The verse follows v.11&apos;s plan-announcement: the plans for welfare have prayer as their medium of access.</p>",
"13": "<p><strong>ûbiqaštĕm ʾōtî ûmĕṣāʾtem kî tidĕrĕšûnnî bĕkol-lĕbabkem</strong> — &quot;You will seek me and find me, when you search for me with all your heart&quot;; the deuteronomic condition (Deut 4:29 — &quot;if you search for him with all your heart and with all your soul&quot;) now stated as a promise rather than a conditional. The MKT&apos;s &quot;when you search for me with all your heart&quot; preserves the shift from &quot;if&quot; to &quot;when&quot; — the conditional has become an assurance. The verb <em>mĕṣāʾtem</em> (you will find) is stated declaratively.</p>",
"14": "<p><strong>wĕnimṣēʾtî lākem</strong> — &quot;I will let myself be found by you&quot;; <em>nimṣēʾtî</em> is the niphal reflexive/passive of <em>māṣāʾ</em> (find): YHWH makes himself findable. The restoration that follows is comprehensive: <em>šabtî ʾet-šĕbûtkem</em> (I will restore your fortunes — the double-<em>šûb</em> formula); gather from all nations; bring back to the place from which I sent you into exile. The MKT translates <em>šabtî ʾet-šĕbûtkem</em> as &quot;restore your fortunes&quot; — the idiom implies a full reversal of all that the exile has taken.</p>",
"15": "<p>The transition: &quot;You may be saying, &apos;The LORD has appointed prophets for us here in Babylon&apos;&quot; — Jeremiah addresses the community&apos;s likely response. The existence of prophets in Babylon is not denied; the question is whether those prophets are authentic. The MKT renders this as a quotation from the community rather than a statement of fact, following the likely sense.</p>",
"16": "<p><strong>yēdaʿ kōh ʾāmar YHWH ʾel-hammelek hayôšēb ʿal-kissēʾ Dāwîd</strong> — &quot;Know that this is what the LORD says concerning the king who sits on David&apos;s throne&quot;; the oracle against those who remained in Jerusalem (vv. 16-19) contrasts with the restoration promised to the exiles (vv. 10-14). Those who stayed behind and claim prophets are still under judgment; those who went into exile hold the covenant promise.</p>",
"17": "<p><strong>hinnĕnî mĕšallaḥ bāhem ʾet-haḥereb wĕʾet-hārāʿāb wĕʾet-haddāber</strong> — &quot;Thus says the LORD: I am going to send sword, famine, and pestilence against them&quot;; the three judgment agents. The image that follows is viscerally unfavorable: &quot;I will make them like rotten figs that are inedible they are so bad&quot; (<em>kattĕʾēnîm hašşōʿārôt ʾăšer lōʾ-tēʾāknâ mērōaʿ</em>). The contrast with the &quot;good figs&quot; of ch. 24 is intentional — those taken to Babylon are good figs; those who stayed are rotten.</p>",
"18": "<p><strong>wĕrādaptî ʾaḥărêhem beḥereb bārāʿāb ûbaddāber</strong> — &quot;I will pursue them with sword, famine, and pestilence&quot;; the verb <em>rādap</em> (pursue) is relentless — judgment will not stop. &quot;I will make them a horror to all the kingdoms of the earth&quot; — <em>lĕzaʿăwâ</em> (horror/trembling), <em>lĕqĕlālâ</em> (curse), <em>lĕšammâ ûlišrēqâ</em> (desolation and hissing). The fourfold shame vocabulary comprehensively captures the social humiliation of covenant curse.</p>",
"19": "<p><strong>yaʿan ʾăšer lōʾ-šāmĕʿû ʾel-dĕbāray</strong> — &quot;because they did not obey my words&quot; — the standard covenant-breach formula. &quot;Which I sent to them persistently through my servants the prophets&quot; (<em>šāllōaḥ wĕšāllōaḥ</em> — the infinitive absolute expressing persistent/repeated sending): YHWH&apos;s messengers came repeatedly; the refusal was persistent. The MKT renders &quot;persistently&quot; to capture the emphatic repetition of the infinitive absolute.</p>",
"20": "<p><strong>wĕʾattem šimĕʿû dĕbar-YHWH kol-haggôlâ</strong> — &quot;So hear the word of the LORD, all you exiles&quot;; the contrast re-established: the exiles who receive the restoration promise (vv. 10-14) are now distinguished from those under judgment (vv. 16-19). The address <em>kol-haggôlâ</em> (all the exile) is the audience for the warning about false prophets that follows.</p>",
"21": "<p><strong>ʾel-ʾAhāb ben-Qôlāyāhû wĕʾel-Ṣidqiyyāhû ben-Maʿăśēyāhû</strong> — specific false prophets in Babylon named and condemned. Unlike Hananiah whose punishment was death within the year, these two are condemned to become a byword: &quot;May the LORD make you like Zedekiah and Ahab, whom the king of Babylon roasted in the fire&quot; (<em>qālāhû... bāʾēš</em>). Execution by fire — they are to be publicly destroyed by the very king they were presumably comforting the exiles about.</p>",
"22": "<p>The curse-formula (<em>qĕlālâ</em>) that will be used by Judean exiles: &quot;May the LORD make you like Zedekiah and Ahab, whom the king of Babylon roasted in the fire.&quot; The false prophets become proverbial — their fate is made into a curse-saying that will outlive them. The MKT preserves <em>qālāhû</em> (roasted) — the stark word for their execution method.</p>",
"23": "<p><strong>yaʿan ʾăšer ʿāśû nĕbālâ bĕYiśrāʾēl</strong> — &quot;because they have done a disgraceful thing in Israel&quot;; <em>nĕbālâ</em> (folly, disgraceful act) is the technical term for sexual immorality and its social-covenant violation. The two charges: adultery with neighbors&apos; wives and speaking false words in YHWH&apos;s name. The combination of sexual and prophetic unfaithfulness mirrors Hosea&apos;s analysis — false prophecy and sexual immorality are paired covenant violations.</p>",
"24": "<p>The Shemaiah episode is introduced: <em>ûlĕŠĕmāʿyāhû hanne-ḥĕlāmî tōʾmar</em> — a new oracle directed against Shemaiah the Nehelamite. The unusual word <em>Nehelamite</em> may be a place name or a word-play on <em>ḥālam</em> (dream) — the &quot;dreamer&quot; prophet. Shemaiah is not in Jerusalem but another exile in Babylon who wrote counter-letters to Jerusalem.</p>",
"25": "<p><strong>yaʿan ʾăšer šālaḥtā sĕpārîm bĕšimkā</strong> — &quot;Because you sent letters in your own name&quot; — Shemaiah&apos;s unauthorized counter-letters, sent in his own name to Jerusalem&apos;s priest Zephaniah, attempted to subvert Jeremiah&apos;s authority. Sending letters <em>bĕšimkā</em> (in your own name) rather than in YHWH&apos;s name marks the self-authorization. The MKT preserves this as the formal charge: letters sent in Shemaiah&apos;s name, not YHWH&apos;s.</p>",
"26": "<p>Shemaiah&apos;s letter claimed that Zephaniah the priest had been appointed to replace Jehoiada &quot;to be in charge of the house of the LORD&quot; (<em>lihyôt pĕquddôt bêt-YHWH</em>) and to deal with any &quot;madman who plays the prophet&quot; (<em>kol-ʾîš mĕšuggāʿ ûmitnaббēʾ</em>). The word for Jeremiah used by Shemaiah — <em>mĕšuggāʿ</em> (madman, disturbed person) — is an insult. The MKT translates it directly as &quot;madman who plays the prophet&quot; to preserve the contemptuous force.</p>",
"27": "<p><strong>lāmmâ lōʾ gāʿartā bĕYirmĕyāhû hāʿănātôtî</strong> — &quot;Why then have you not rebuked Jeremiah of Anathoth?&quot; Shemaiah names Jeremiah with his village origin — &quot;of Anathoth&quot; — perhaps a further diminishment (a provincial prophet). The expected response: Zephaniah should have used his priestly authority to silence Jeremiah. That he did not is what Shemaiah&apos;s letter is designed to correct.</p>",
"28": "<p><strong>kî ʿal-kēn šālaḥ ʾēlênû Bābĕlâ</strong> — &quot;For he has sent word to us in Babylon, saying: Your exile will be long (<em>ʾārkâ</em>)&quot;; Shemaiah quotes Jeremiah&apos;s letter (29:5-7) — build houses, plant gardens. The instruction to settle in for a long exile is what Shemaiah finds intolerable. The word <em>ʾārkâ</em> (long, extended) is Shemaiah&apos;s characterization of Jeremiah&apos;s message — and it is accurate. The MKT follows the quoted speech.</p>",
"29": "<p>Zephaniah read the letter aloud to Jeremiah — the priest showed Jeremiah the letter rather than acting on it. The implication: Zephaniah is not an enemy of Jeremiah, even if Shemaiah wanted him to be. The MKT preserves the &quot;aloud&quot; reading because it implies that the letter was read in Jeremiah&apos;s hearing as an act of informing rather than condemning him.</p>",
"30": "<p>The standard prophetic formula introduces the divine response to Shemaiah: <em>wayĕhî dĕbar-YHWH ʾel-yirmĕyāhû lēʾmōr</em>. The sequence: Shemaiah&apos;s unauthorized letter → Zephaniah reads it to Jeremiah → YHWH speaks to Jeremiah about Shemaiah. YHWH responds to private opposition to his prophet with public divine judgment, just as with Hananiah.</p>",
"31": "<p><strong>šĕlaḥ ʾel-kol-haggôlâ lēʾmōr</strong> — &quot;Send word to all the exiles&quot;; Jeremiah is to broadcast the judgment against Shemaiah publicly — to all the exiles, not just to Zephaniah or to Shemaiah privately. The reason for the public condemnation: <em>yaʿan ʾăšer nibbā lākem Šĕmāʿyāhû wĕʾānōkî lōʾ-šĕlaḥtîw</em> — &quot;because Shemaiah has prophesied to you and I did not send him.&quot; The core criterion: <em>lōʾ šĕlaḥtîw</em> — unsent prophecy is false prophecy.</p>",
"32": "<p><strong>lāken kōh-ʾāmar YHWH hinnĕnî pōqēd ʿal-Šĕmāʿyāhû</strong> — &quot;Therefore thus says the LORD: I am going to punish Shemaiah the Nehelamite and his descendants&quot;; three punishments: none of his descendants will survive (<em>lōʾ-yihyeh lô ʾîš yôšēb bĕtôk hāʿām hazzeh</em>), he will not see the good YHWH does for his people, and he will not return from exile. The punishment for opposing the covenant promise: exclusion from the very blessing he attempted to hasten by false prophecy.</p>"
},
"30": {
"1": "<p>The Book of Consolation begins (chs. 30-33) with the standard formula: <em>haddābār ʾăšer hāyâ ʾel-yirmĕyāhû mēʾēt YHWH lēʾmōr</em>. The shift from judgment oracles to restoration oracles marks a decisive turn. The MKT preserves the formula as the opening of a new section rather than continuing the letter-narrative of ch. 29.</p>",
"2": "<p><strong>kŏh ʾāmar YHWH ʾĕlōhê Yiśrāʾēl lēʾmōr kŏtāb-lĕkā ʾēt kol-haddĕbārîm ʾăšer dibbartî ʾēlêkā ʾel-sēper</strong> — &quot;Write in a book all the words I have spoken to you&quot;; the command to write (<em>kĕtōb lĕkā ʾel-sēper</em>) creates a document — the consolation oracles are not merely spoken but preserved. The Book of Consolation is thus a self-consciously created literary unit. The MKT renders &quot;write in a book&quot; rather than &quot;write on a scroll&quot; for readability, though <em>sēper</em> most naturally refers to a scroll in this period.</p>",
"3": "<p><strong>kî hinnēh yāmîm bāʾîm nĕʾum-YHWH wĕšabtî ʾet-šĕbût ʿammî Yiśrāʾēl ûYĕhûdâ</strong> — &quot;For the days are coming, declares the LORD, when I will restore the fortunes of my people Israel and Judah&quot;; <em>šabtî ʾet-šĕbût</em> — the double-<em>šûb</em> restoration formula. Both northern Israel (<em>Yiśrāʾēl</em>) and southern Judah (<em>Yĕhûdâ</em>) are included in the restoration — the divided kingdom reunified. The phrase <em>wĕhăšibōtîm ʾel-hāʾārets ʾăšer-nātattî laʾăbôtām wîrĕšûhā</em> — &quot;I will bring them back to the land I gave their ancestors, and they will take possession of it.&quot;</p>",
"4": "<p>The structural marker introducing the poetry that follows: <em>wĕʾēlleh haddĕbārîm ʾăšer dibbēr YHWH ʾel-Yiśrāʾēl wĕʾel-Yĕhûdâ</em> — &quot;These are the words the LORD spoke concerning Israel and Judah.&quot; The transition from prose (vv. 1-3) to poetry (vv. 5-7) is introduced formally. The audience is both kingdoms together — the eschatological vision overrides the historical division.</p>",
"5": "<p><strong>qôl ḥarādâ šāmāʿnû paḥad wĕʾên šālôm</strong> — &quot;We have heard a cry of terror, of dread — not of peace&quot;; the Book of Consolation begins paradoxically with a terror oracle. Before the restoration comes &quot;Jacob&apos;s trouble&quot; (v.7). The word <em>ḥarādâ</em> (terror, trembling) and <em>paḥad</em> (dread, fear) establish the severity of what must be endured before the restoration. <em>Wĕʾên šālôm</em> — &quot;and there is no peace&quot; — the peace Hananiah falsely promised is genuinely absent in the time of trouble.</p>",
"6": "<p><strong>šaʾălû-nāʾ ûrĕʾû ʾim-yōlēd zākār</strong> — &quot;Ask yourselves and look: can a man give birth?&quot; The rhetorical impossibility: a man cannot give birth; yet every man is clutching his sides <em>kĕyôlēdâ</em> (like a woman in labor) and faces have turned pale (<em>nehĕpĕkû kol-pānîm lĕyērāqôn</em>). The unprecedented nature of the coming distress is conveyed by an image of gender reversal — men experiencing birth pangs. The MKT preserves the rhetorical question to maintain the shock of the image.</p>",
"7": "<p><strong>ʾôy kî gādôl hayyôm hahûʾ mēʾên kāmōhû</strong> — &quot;How terrible that day will be! There has never been another like it&quot;; <em>ʾôy</em> (woe/alas) opens the verse. The phrase <em>wĕʾēt-ṣārâ hîʾ lĕYaʿăqōb</em> — &quot;It is a time of anguish for Jacob&quot; — the phrase &quot;time of Jacob&apos;s trouble&quot; used in subsequent eschatological interpretation. The climactic assurance: <em>ûmimmennâ yiwwāšēaʿ</em> — &quot;but he will be saved from it.&quot; The salvation comes through the trouble, not around it. The MKT renders &quot;anguish&quot; for <em>ṣārâ</em> (distress, trouble, straits).</p>",
"8": "<p><strong>wĕhāyâ bayyôm hahûʾ nĕʾum YHWH ṣĕbāʾôt ʾešbōr ʿullô mēʿal ṣawwāʾrekā</strong> — &quot;On that day, declares the LORD of hosts, I will break the yoke from your neck&quot;; the same vocabulary as Hananiah&apos;s false promise (28:2) — but now YHWH genuinely promises it for the eschatological day. Hananiah&apos;s premature &quot;I have broken the yoke&quot; will be truly fulfilled in the future YHWH envisions. The MKT&apos;s translation preserves the verbal echo of ch. 28.</p>",
"9": "<p><strong>wĕʿābĕdû ʾēt YHWH ʾĕlōhêhem wĕʾēt Dāwîd malkām ʾăšer ʾāqîm lāhem</strong> — &quot;Instead they will serve the LORD their God and David their king, whom I will raise up for them&quot;; the Davidic restoration: <em>Dāwîd malkām ʾăšer ʾāqîm lāhem</em> — David their king whom I will raise up. Since David has been dead for centuries, this must refer to a Davidic heir whom YHWH will &quot;raise up&quot; (<em>qûm</em> in the hiphil). The phrase <em>ʾăšer ʾāqîm lāhem</em> (whom I will raise up for them) makes the Davidic king a divine gift given in the future, not a continuation of the present dynasty. The MKT preserves the future-oriented language of divine raising-up.</p>",
"10": "<p><strong>wĕʾattâ ʾal-tîrāʾ ʿabdî Yaʿăqōb nĕʾum YHWH</strong> — &quot;So do not be afraid, my servant Jacob, declares the LORD&quot;; the divine reassurance formula &quot;Do not fear&quot; (<em>ʾal-tîrāʾ</em>) addressed to &quot;my servant Jacob&quot; (<em>ʿabdî Yaʿăqōb</em>) — the servant-language for the nation. &quot;For I am going to save you from far away, your descendants from the land of their exile&quot; — the restoration is a rescue from <em>mērāḥôq</em> (far away), from all the lands of exile. The parallel &quot;Jacob will return to safety&quot; (<em>wĕšāb Yaʿăqōb wĕšāqaṭ</em>) — <em>šāqaṭ</em> means to be quiet/at rest, the opposite of the terror described in vv. 5-7.</p>",
"11": "<p><strong>kî ʾittĕkā ʾānî nĕʾum YHWH lĕhôšîʿekā</strong> — &quot;For I am with you, declares the LORD, to save you&quot;; the &apos;immanuel&apos;-formula (&quot;I am with you&quot;) as the ground of salvation. Three assurances: YHWH with Jacob, full destruction of the nations where scattered, discipline of Jacob in just measure. <em>Wĕyissar tĕkā lammišpāṭ</em> — &quot;I will discipline you in just measure&quot; (<em>lammišpāṭ</em> = according to justice). The guarantee: <em>wĕnaqkeh lōʾ ʾănaqkek</em> — &quot;I will by no means leave you unpunished&quot; — the discipline is real but bounded, not annihilation.</p>",
"12": "<p><strong>kōh ʾāmar YHWH ʾānûš lĕšibrĕkā naḥlâ makkātēk</strong> — &quot;For thus says the LORD: Your injury is incurable, your wound is severe&quot;; <em>ʾānûš</em> (incurable, desperately sick) — the same word used of the heart in 17:9. The wound (<em>makkâ</em>) is described with the word for a blow struck in battle: YHWH has struck Israel as an enemy would strike. The shift from restoration promise (vv. 8-11) to wound-description (vv. 12-15) creates a dialectical movement — the wound must be acknowledged before the healing can be received.</p>",
"13": "<p><strong>ʾên-dān dînēk lĕmĕzôr rĕpuʾôt tĕʿālâ ʾên lāk</strong> — &quot;There is no one to plead your case; you have no medicines for your wound — no recovery for you&quot;; <em>dān dînēk</em> (pleading your case) — no advocate; <em>mĕzôr</em> (medicines for a wound, a compress) — no physician. The medical vocabulary frames the wound as both legally and physically unaddressable by human means. The hopelessness established here makes YHWH&apos;s healing promise in v.17 all the more radical.</p>",
"14": "<p><strong>kol-mĕʾahăbayik šĕkēḥûk</strong> — &quot;All your allies have abandoned you; they no longer care about you&quot;; <em>mĕʾahăbayik</em> (your lovers/allies) — the political allies who were to provide security have forgotten Israel. The wound described: YHWH struck Israel <em>makkâ ʾôyēb</em> — &quot;the blow of an enemy&quot; — and <em>mûsar ʾakzārî</em> — &quot;the punishment of a cruel one.&quot; The terrible irony: the enemy-blow comes from YHWH himself, not from the nations alone.</p>",
"15": "<p><strong>mah-tizʿaq ʿal-šibrĕk ʾānûš maʿkōbēk</strong> — &quot;Why do you cry out over your wound? Your pain is incurable&quot;; the diagnostic: the crying is understandable, but the cause is the people&apos;s own sin: <em>ʿal rōb ʿăwōnēk ʿāṣĕmû ḥaṭṭōʾtayik</em> — &quot;because your guilt is great and your sins are many, I have done these things to you.&quot; The covenant-justice explanation for the incurable wound: the severity of the wound is proportional to the severity of the sin.</p>",
"16": "<p><strong>lākēn kol-ʾōkelayik yēʾākēlû</strong> — &quot;Therefore all who devour you will be devoured&quot;; the reversal oracle begins with a <em>lākēn</em> (therefore) that pivots from diagnosis to restoration. The three reversals: devouring devourers; captive captors; plundering plunderers — each attacker is subjected to the same fate they inflicted. The MKT preserves the wordplay in each pair (devour/devoured, captive/captivity, plunder/plundered).</p>",
"17": "<p><strong>kî ʾaʿăleh ʾărûkâ lāk ûmimmakkôtayik ʾerpāʾēk nĕʾum YHWH</strong> — &quot;For I will restore your health and heal your wounds, declares the LORD&quot;; <em>ʾārûkâ</em> (new skin, healing, health) — the medical term for recovery from a wound. The reason for healing: <em>kî niddāḥâ qārĕʾû lāk</em> — &quot;because they called you Outcast (<em>niddāḥâ</em>), &apos;Zion for whom no one cares&apos;&quot; — the social shame of abandonment becomes YHWH&apos;s motivation for intervention. YHWH heals Zion precisely because the nations have written her off. The MKT renders <em>niddāḥâ</em> as &quot;Outcast.&quot;</p>",
"18": "<p><strong>hinnî-šāb šĕbût ʾohŏlê Yaʿăqōb</strong> — &quot;Thus says the LORD: I am going to restore the fortunes of Jacob&apos;s tents&quot;; <em>šĕbût</em> is here used again — the restoration formula (cf. v.3). The specific images: the city (<em>ʿîr</em>) will be rebuilt on its mound (<em>tel</em>); the palace (<em>ʾarmôn</em>) will stand in its rightful place. <em>Tūrăm al-mišpāṭām</em> — &quot;on its own site, in its rightful place&quot; — the restoration is to the same location, not relocation to somewhere else.</p>",
"19": "<p><strong>wĕyāṣāʾ mēhem tôdâ wĕqôl mĕśaḥăqîm</strong> — &quot;From them will come songs of thanksgiving and the sound of rejoicing&quot;; the acoustic image of restoration: <em>tôdâ</em> (thanksgiving, praise) and <em>qôl mĕśaḥăqîm</em> (sound of those who make merry). &quot;I will multiply them so that they will not be few; I will honor them so that they will not be small&quot; — the reversed direction: from decrease to increase, from humiliation to honor. The MKT renders both pairs to preserve the doublet structure.</p>",
"20": "<p><strong>wĕhāyû bānāyw kĕqedem</strong> — &quot;Their children will be as they were in former times&quot; (<em>kĕqedem</em>, as in the former days); the restoration of the ancestral community pattern. <em>Wĕʿēdātô lĕpānay tikkôn</em> — &quot;their congregation will be established before me&quot; — the covenantal assembly restored. &quot;And I will punish all who oppress them&quot; — the covenant protection against oppressors is reimposed.</p>",
"21": "<p><strong>wĕhāyâ ʾaddîrô mimmennû ûmōšĕlô miqirbô yēṣēʾ</strong> — &quot;Their leader will come from among them, and their governor will emerge from their own midst&quot;; <em>ʾaddîr</em> (mighty one, noble leader) and <em>mōšēl</em> (ruler, governor) — both from among the people, not from a foreign power. The phrase <em>wĕhiqqarbtîw wĕniggaš ʾēlay</em> — &quot;I will bring him near, and he will approach me&quot; — priestly language: <em>niggaš ʾēlay</em> means drawing near to YHWH in the way a priest draws near. The leader who is both ruler and priestly-access figure anticipates the Christological theme of Melchizedek-priest-king. The MKT renders &quot;approach me&quot; to preserve the theologically loaded <em>nāgaš</em> (draw near) vocabulary.</p>",
"22": "<p><strong>wîhîtem lî lĕʿām wĕʾānōkî ʾehyeh lākem lēʾlōhîm</strong> — &quot;You will be my people, and I will be your God&quot;; the covenant formula in its shortest and most compressed form. The bilateral structure: your people (<em>lĕʿām</em>) / your God (<em>lēʾlōhîm</em>). This formula appears at the heart of the covenant (Exod 6:7; Lev 26:12; Deut 26:17-18) and marks its climactic restoration in both Jeremiah (31:33) and Ezekiel (36:28). Its placement here, mid-consolation, anchors the entire restoration to the covenant relationship.</p>",
"23": "<p><strong>hinnēh saʿărat YHWH ḥēmâ yāṣĕʾāh saʿar mitgôrēr</strong> — &quot;See, the storm of the LORD! His wrath has gone forth, a sweeping whirlwind&quot;; an intrusion of the judgment oracle before the final climax. <em>Saʿar</em> (storm, whirlwind) and <em>mitgôrēr</em> (sweeping, swirling) — the storm imagery for YHWH&apos;s judgment (cf. 23:19). &quot;It will break upon the head of the wicked&quot; (<em>ʿal rōʾš rĕšāʿîm yāḥûl</em>). The storm oracle is not against Israel but against the nations and the wicked — the same wrath that judged Israel will fall on oppressors. The MKT renders the storm vocabulary consistently with its appearance in ch. 23.</p>",
"24": "<p><strong>lōʾ yāšûb ḥărôn ʾap-YHWH ʿad-ʿăśōtô wĕʿad-hăqîmô mĕzimmôt libbô</strong> — &quot;The fierce anger of the LORD will not turn back until he has done and performed the purposes of his heart&quot;; <em>mĕzimmôt libbô</em> — the purposes/devices of YHWH&apos;s heart — what YHWH plans will be executed. The closing phrase: <em>bĕʾaḥărît hayyāmîm tĕtbônănû bāh</em> — &quot;In the latter days you will understand this&quot; — the consolation and the storm alike will become clear at the end. The MKT renders <em>ʾaḥărît hayyāmîm</em> as &quot;the latter days&quot; (the standard eschatological phrase) and <em>tĕtbônănû</em> (you will understand/perceive it) to preserve the future comprehension promised.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'jeremiah')
    merge_comm(existing, JEREMIAH)
    save_comm('mkt-original', 'jeremiah', existing)
    print('Jeremiah 28-30 mkt-original written.')

if __name__ == '__main__':
    main()
